import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Container, Navbar, Nav, Button, Modal, Card, Table } from 'react-bootstrap';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'react-toastify';
import { 
  Upload, 
  Search, 
  FileText, 
  LogOut, 
  User,
  Settings,
  Clock,
  Calendar,
  Shield,
  BarChart3
} from 'lucide-react';
import DocumentUpload from './DocumentUpload';
import DocumentRetrieval from './DocumentRetrieval';
import LetterTemplates from './LetterTemplates';
import CategoryManagement from './CategoryManagement';
import ExpiryDashboard from './ExpiryDashboard';
import ComplianceDashboard from './ComplianceDashboard';
import './Dashboard.css';

const Dashboard = () => {
  const [activeMenu, setActiveMenu] = useState('compliance-dashboard');
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const [currentDateTime, setCurrentDateTime] = useState(new Date());
  
  // Auto logout state
  const [showWarningModal, setShowWarningModal] = useState(false);
  const [remainingTime, setRemainingTime] = useState(60);
  const logoutTimerRef = useRef(null);
  const warningTimerRef = useRef(null);
  const countdownRef = useRef(null);
  const lastActivityRef = useRef(Date.now());

  const IDLE_TIMEOUT = 10 * 60 * 1000; // 10 minutes
  const WARNING_TIME = 60 * 1000; // 1 minute warning

  // Update date/time every second
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentDateTime(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const handleAutoLogout = useCallback(() => {
    logout();
    toast.warning('You have been logged out due to inactivity', {
      position: 'top-right',
      autoClose: 3000
    });
    navigate('/login');
  }, [logout, navigate]);

  const resetTimers = useCallback(() => {
    // Clear existing timers
    if (logoutTimerRef.current) clearTimeout(logoutTimerRef.current);
    if (warningTimerRef.current) clearTimeout(warningTimerRef.current);
    if (countdownRef.current) clearInterval(countdownRef.current);

    // Hide warning modal if showing
    setShowWarningModal(false);
    setRemainingTime(60);

    // Update last activity time
    lastActivityRef.current = Date.now();

    // Set warning timer (9 minutes)
    warningTimerRef.current = setTimeout(() => {
      setShowWarningModal(true);
      setRemainingTime(60);

      // Start countdown
      countdownRef.current = setInterval(() => {
        setRemainingTime(prev => {
          if (prev <= 1) {
            clearInterval(countdownRef.current);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);

      // Set logout timer (1 minute after warning)
      logoutTimerRef.current = setTimeout(() => {
        handleAutoLogout();
      }, WARNING_TIME);
    }, IDLE_TIMEOUT - WARNING_TIME);
  }, [handleAutoLogout]);

  // Setup auto logout
  useEffect(() => {
    resetTimers();

    // Activity events
    const events = ['mousedown', 'mousemove', 'keypress', 'scroll', 'touchstart', 'click'];

    const handleActivity = () => {
      resetTimers();
    };

    // Add event listeners
    events.forEach(event => {
      document.addEventListener(event, handleActivity);
    });

    // Cleanup
    return () => {
      events.forEach(event => {
        document.removeEventListener(event, handleActivity);
      });
      if (logoutTimerRef.current) clearTimeout(logoutTimerRef.current);
      if (warningTimerRef.current) clearTimeout(warningTimerRef.current);
      if (countdownRef.current) clearInterval(countdownRef.current);
    };
  }, [resetTimers]);

  const handleContinueSession = () => {
    resetTimers();
  };

  const handleLogout = () => {
    // Clear all timers
    if (logoutTimerRef.current) clearTimeout(logoutTimerRef.current);
    if (warningTimerRef.current) clearTimeout(warningTimerRef.current);
    if (countdownRef.current) clearInterval(countdownRef.current);

    logout();
    toast.success('Successfully Logged Out', {
      position: 'top-right',
      autoClose: 2000
    });
    setTimeout(() => {
      navigate('/login');
    }, 1000);
    setShowLogoutModal(false);
  };

  const menuItems = [
    
    { 
      id: 'upload', 
      label: 'Document Upload', 
      icon: Upload
    },
    { 
      id: 'search', 
      label: 'Document Retrieval & Search', 
      icon: Search
    },
    {
      id: 'compliance-dashboard',
      label: 'Compliance Dashboard',
      icon: BarChart3
    },
    {
      id: 'expiry-tracking',
      label: 'Expiry Tracking System',
      icon: Clock
    },
    { 
      id: 'templates', 
      label: 'Letter Templates & Printing', 
      icon: FileText
    },
    { 
      id: 'categories', 
      label: 'Category Management', 
      icon: Settings
    },
    {
      id: 'access-matrix',
      label: 'Access Control Matrix',
      icon: Shield
    }
  ];

  const accessMatrix = [
    { feature: 'Document Upload & Management', admin: 'âœ”ï¸ All Stores', hr: 'âœ”ï¸ All Stores', storeManager: 'âœ”ï¸ Own Store Only' },
    { feature: 'Document Search & Retrieval', admin: 'âœ”ï¸ All Stores', hr: 'âœ”ï¸ All Stores', storeManager: 'âœ”ï¸ Own Store Only' },
    { feature: 'Expiry Tracking & Notifications', admin: 'âœ”ï¸ Full Access', hr: 'âœ”ï¸ Full Access', storeManager: 'âœ”ï¸ Own Store Only' },
    { feature: 'Letter Templates & Printing', admin: 'âœ”ï¸ Add / Edit', hr: 'âœ”ï¸ Use & Edit', storeManager: 'âŒ Not Allowed' },
    { feature: 'User Management & Access Control', admin: 'âœ”ï¸ Full Access', hr: 'âŒ Not Allowed', storeManager: 'âŒ Not Allowed' },
    { feature: 'Audit Support & Reporting', admin: 'âœ”ï¸ Full Access', hr: 'âœ”ï¸ Full Access', storeManager: 'âŒ Not Allowed' },
    { feature: 'Onboarding Module', admin: 'âœ”ï¸ All Stores', hr: 'âœ”ï¸ All Stores', storeManager: 'âœ”ï¸ Own Store Only' },
    { feature: 'Offboarding Module', admin: 'âœ”ï¸ All Stores', hr: 'âœ”ï¸ All Stores', storeManager: 'âœ”ï¸ Own Store Only' },
    { feature: 'Approval Workflow Module', admin: 'Final Approver', hr: 'Middle Approver', storeManager: 'Initial Approver' },
    { feature: 'Bulk Document Download', admin: 'âœ”ï¸ Allowed', hr: 'âœ”ï¸ Allowed', storeManager: 'âŒ Not Allowed' },
    { feature: 'Activity / Audit Log View', admin: 'âœ”ï¸ Allowed', hr: 'âœ”ï¸ Allowed', storeManager: 'âŒ Not Allowed' },
    { feature: 'Store-Based Restriction Handling', admin: 'âœ”ï¸ Configure', hr: 'âœ”ï¸ Monitor', storeManager: 'âœ”ï¸ Enforce' }
  ];

  const renderAccessMatrix = () => {
    return (
      <Card className="access-matrix-main-card">
        <Card.Header className="card-header-custom">
          <h3 className="mb-0">
            <Shield className="me-2" size={24} />
            Access Control Matrix
          </h3>
        </Card.Header>
        <Card.Body>
          <div className="alert alert-info mb-4">
            <strong>â„¹ï¸ About Access Matrix:</strong> This table shows the permission levels for different user roles across all modules in the system.
          </div>
          
          <div className="table-responsive">
            <Table bordered hover className="access-matrix-table">
              <thead>
                <tr>
                  <th style={{ width: '40%' }}><strong>Module / Feature</strong></th>
                  <th className="text-center" style={{ width: '20%' }}>
                    <div className="role-header">
                      <User size={18} className="mb-1" />
                      <div><strong>Admin</strong></div>
                    </div>
                  </th>
                  <th className="text-center" style={{ width: '20%' }}>
                    <div className="role-header">
                      <User size={18} className="mb-1" />
                      <div><strong>HR</strong></div>
                    </div>
                  </th>
                  <th className="text-center" style={{ width: '20%' }}>
                    <div className="role-header">
                      <User size={18} className="mb-1" />
                      <div><strong>Store Manager</strong></div>
                    </div>
                  </th>
                </tr>
              </thead>
              <tbody>
                {accessMatrix.map((row, idx) => (
                  <tr key={idx}>
                    <td className="feature-name">
                      <strong>{row.feature}</strong>
                    </td>
                    <td className="text-center">
                      {row.admin.includes('âœ”ï¸') ? (
                        <span className="badge bg-success px-3 py-2">{row.admin}</span>
                      ) : (
                        <span className="badge bg-secondary px-3 py-2">{row.admin}</span>
                      )}
                    </td>
                    <td className="text-center">
                      {row.hr.includes('âœ”ï¸') ? (
                        <span className="badge bg-success px-3 py-2">{row.hr}</span>
                      ) : row.hr.includes('âŒ') ? (
                        <span className="badge bg-danger px-3 py-2">{row.hr}</span>
                      ) : (
                        <span className="badge bg-warning px-3 py-2">{row.hr}</span>
                      )}
                    </td>
                    <td className="text-center">
                      {row.storeManager.includes('âœ”ï¸') ? (
                        <span className="badge bg-success px-3 py-2">{row.storeManager}</span>
                      ) : row.storeManager.includes('âŒ') ? (
                        <span className="badge bg-danger px-3 py-2">{row.storeManager}</span>
                      ) : (
                        <span className="badge bg-info px-3 py-2">{row.storeManager}</span>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </Table>
          </div>

          <div className="mt-4">
            <h5>Legend:</h5>
            <div className="d-flex gap-3 flex-wrap">
              <div><span className="badge bg-success">âœ”ï¸ Allowed</span> - Full or restricted access granted</div>
              <div><span className="badge bg-danger">âŒ Not Allowed</span> - Access denied</div>
              <div><span className="badge bg-warning">Warning</span> - Middle level approval</div>
              <div><span className="badge bg-info">Info</span> - Role-specific access</div>
            </div>
          </div>
        </Card.Body>
      </Card>
    );
  };

  const renderContent = () => {
    switch (activeMenu) {
      case 'compliance-dashboard':
        return <ComplianceDashboard />;
      case 'upload':
        return <DocumentUpload />;
      case 'search':
        return <DocumentRetrieval />;
      case 'expiry-tracking':
        return <ExpiryDashboard />;
      case 'templates':
        return <LetterTemplates />;
      case 'categories':
        return <CategoryManagement />;
      case 'access-matrix':
        return renderAccessMatrix();
      default:
        return <ComplianceDashboard />;
    }
  };

  return (
    <div className="dashboard-container">
      <Navbar bg="primary" variant="dark" className="dashboard-header">
        <Container fluid>
          <Navbar.Brand className="dashboard-brand">
            <FileText size={28} className="me-2" />
            Centralized Employee Document Management System
          </Navbar.Brand>
          <Nav className="ms-auto align-items-center">
            <div className="user-info me-3">
              <User size={20} className="me-2" />
              <span>{user?.name || 'HR User'}</span>
            </div>
            <Button
              variant="outline-light"
              onClick={() => setShowLogoutModal(true)}
              className="logout-btn"
            >
              <LogOut size={18} className="me-2" />
              Logout
            </Button>
          </Nav>
        </Container>
      </Navbar>

      <div className="dashboard-body">
        <div className="dashboard-sidebar">
          <Card className="info-card mb-3 mx-3 mt-3">
            <Card.Body className="py-3">
              <div className="d-flex align-items-center mb-3">
                <div className="user-avatar me-3">
                  <User size={32} />
                </div>
                <div>
                  <h6 className="mb-0">{user?.name || 'HR User'}</h6>
                  <small className="text-muted">{user?.role || 'HR'} Role</small>
                </div>
              </div>
              <div className="datetime-section">
                <div className="d-flex align-items-center mb-2">
                  <Calendar size={14} className="me-2 text-primary" />
                  <small className="fw-bold">
                    {currentDateTime.toLocaleDateString('en-US', { 
                      weekday: 'short', 
                      year: 'numeric', 
                      month: 'short', 
                      day: 'numeric' 
                    })}
                  </small>
                </div>
                <div className="d-flex align-items-center">
                  <Clock size={14} className="me-2 text-primary" />
                  <small className="fw-bold">
                    {currentDateTime.toLocaleTimeString('en-US', { 
                      hour: '2-digit', 
                      minute: '2-digit',
                      second: '2-digit',
                      hour12: true 
                    })}
                  </small>
                </div>
              </div>
            </Card.Body>
          </Card>

          <Nav className="flex-column sidebar-nav">
            {menuItems.map((item) => {
              const Icon = item.icon;
              const isActive = activeMenu === item.id;
              
              return (
                <Nav.Link
                  key={item.id}
                  onClick={() => setActiveMenu(item.id)}
                  className={`sidebar-item ${isActive ? 'active' : ''}`}
                >
                  <div className="d-flex align-items-center">
                    <Icon size={18} className="me-2" />
                    <span style={{ fontSize: '0.9rem' }}>{item.label}</span>
                  </div>
                </Nav.Link>
              );
            })}
          </Nav>
        </div>

        <div className="dashboard-content">
          <Container fluid className="py-4">
            {renderContent()}
          </Container>
        </div>
      </div>

      {/* Logout Confirmation Modal */}
      <Modal show={showLogoutModal} onHide={() => setShowLogoutModal(false)} centered>
        <Modal.Header closeButton>
          <Modal.Title>Confirm Logout</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          Are you sure you want to logout?
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={() => setShowLogoutModal(false)}>
            Cancel
          </Button>
          <Button variant="primary" onClick={handleLogout}>
            Logout
          </Button>
        </Modal.Footer>
      </Modal>

      {/* Auto Logout Warning Modal */}
      <Modal 
        show={showWarningModal} 
        onHide={() => {}} 
        backdrop="static" 
        keyboard={false}
        centered
      >
        <Modal.Header>
          <Modal.Title>Session Timeout Warning</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <div className="text-center">
            <Clock size={48} className="text-warning mb-3" />
            <p>Your session will expire in:</p>
            <h2 className="text-danger">{remainingTime} seconds</h2>
            <p className="text-muted">Click "Continue" to stay logged in</p>
          </div>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="primary" onClick={handleContinueSession}>
            Continue Session
          </Button>
          <Button variant="secondary" onClick={handleAutoLogout}>
            Logout Now
          </Button>
        </Modal.Footer>
      </Modal>
    </div>
  );
};

export default Dashboard;
